class InteractionTracker extends NavigatorObserver {
  @override
  void didPush(Route<dynamic> route, Route<dynamic>? previousRoute) {
    AppLogger.userInteraction(
      event: 'navigation_push',
      screen: route.settings.name,
      data: {
        'previous': previousRoute?.settings.name,
      },
    );
    super.didPush(route, previousRoute);
  }

  @override
  void didPop(Route<dynamic> route, Route<dynamic>? previousRoute) {
    AppLogger.userInteraction(
      event: 'navigation_pop',
      screen: previousRoute?.settings.name,
      data: {
        'popped': route.settings.name,
      },
    );
    super.didPop(route, previousRoute);
  }
}

